using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace WeatherMcpServer;

[McpServerToolType]
public class WeatherTools(HttpClient httpClient, ILogger<WeatherTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Get the current weather forecast for a city. Returns temperature, conditions, and humidity.")]
    public async Task<string> GetCurrentWeather(
        [Description("City name, e.g. 'London' or 'New York'")] string city,
        [Description("Temperature unit: 'celsius' or 'fahrenheit'. Defaults to celsius.")] string units = "celsius",
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching weather for {City} in {Units}", city, units);

        var unitParam = units.Equals("fahrenheit", StringComparison.OrdinalIgnoreCase)
            ? "imperial" : "metric";

        var response = await httpClient.GetAsync(
            $"/v1/weather?city={Uri.EscapeDataString(city)}&units={unitParam}",
            cancellationToken);

        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Get a multi-day weather forecast for a city.")]
    public async Task<string> GetForecast(
        [Description("City name, e.g. 'Tokyo'")] string city,
        [Description("Number of days to forecast (1-7)")] int days = 3,
        CancellationToken cancellationToken = default)
    {
        days = Math.Clamp(days, 1, 7);
        logger.LogInformation("Fetching {Days}-day forecast for {City}", days, city);

        var response = await httpClient.GetAsync(
            $"/v1/forecast?city={Uri.EscapeDataString(city)}&days={days}",
            cancellationToken);

        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool(ReadOnly = true), Description("List all supported cities for weather queries.")]
    public async Task<string> ListSupportedCities(
        CancellationToken cancellationToken = default)
    {
        var response = await httpClient.GetAsync("/v1/cities", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

